const raw = $input.first().json;
const body = raw.body || raw;

const payload = {
  taskId: String(body.taskId || '').trim(),
  studentId: String(body.studentId || '').trim(),
  studentName: String(body.studentName || '').trim(),
  lichessId: String(body.lichessId || '').trim(),
  month: String(body.month || '').trim(),
  monthKey: String(body.monthKey || '').trim()
};

if (!payload.lichessId) throw new Error('Lichess ID is required.');

function parseMonth(inputMonth, inputMonthKey) {
  if (inputMonthKey && /^\d{4}-\d{2}$/.test(inputMonthKey)) {
    return new Date(`${inputMonthKey}-01T00:00:00.000Z`);
  }
  const direct = inputMonth ? new Date(inputMonth) : null;
  if (direct && !Number.isNaN(direct.getTime())) return direct;
  const named = inputMonth ? new Date(`1 ${inputMonth}`) : null;
  if (named && !Number.isNaN(named.getTime())) return named;
  return new Date();
}

const base = parseMonth(payload.month, payload.monthKey);
const start = new Date(Date.UTC(base.getUTCFullYear(), base.getUTCMonth(), 1, 0, 0, 0, 0));
const end = new Date(Date.UTC(base.getUTCFullYear(), base.getUTCMonth() + 1, 1, 0, 0, 0, 0));

payload.since = start.getTime();
payload.until = end.getTime();
payload.monthKey = `${start.getUTCFullYear()}-${String(start.getUTCMonth() + 1).padStart(2, '0')}`;
payload.monthLabel = start.toLocaleString('en-IN', { month: 'long', year: 'numeric', timeZone: 'UTC' });
payload.encodedLichessId = encodeURIComponent(payload.lichessId);

return [{ json: payload }];

const request = $items('Normalize V2 Request')[0].json;
const profile = $items('Fetch Lichess Profile')[0].json || {};
const gamesRaw = $items('Fetch Lichess Games')[0].json;

const gamesText = typeof gamesRaw === 'string'
  ? gamesRaw
  : (gamesRaw && typeof gamesRaw.data === 'string' ? gamesRaw.data : String(gamesRaw || ''));

const games = String(gamesText || '').trim()
  ? String(gamesText).trim().split(/\n+/).map((line) => {
      try { return JSON.parse(line); } catch (error) { return null; }
    }).filter(Boolean)
  : [];

const username = String(request.lichessId || '').trim();
const userLower = username.toLowerCase();
let wins = 0;
let draws = 0;
let losses = 0;
let ratingDiffTotal = 0;
let ratingDiffCount = 0;
let bestWin = null;
const perfCounts = {};

for (const game of games) {
  const whiteName = String(game.players?.white?.user?.name || game.players?.white?.user?.id || '').toLowerCase();
  const blackName = String(game.players?.black?.user?.name || game.players?.black?.user?.id || '').toLowerCase();
  const color = whiteName === userLower ? 'white' : (blackName === userLower ? 'black' : '');
  if (!color) continue;

  const opponentColor = color === 'white' ? 'black' : 'white';
  const player = game.players?.[color] || {};
  const opponent = game.players?.[opponentColor] || {};
  const perf = String(game.perf || 'standard');
  perfCounts[perf] = (perfCounts[perf] || 0) + 1;

  if (typeof player.ratingDiff === 'number') {
    ratingDiffTotal += player.ratingDiff;
    ratingDiffCount += 1;
  }

  if (!game.winner) {
    draws += 1;
  } else if (game.winner === color) {
    wins += 1;
    const opponentRating = Number(opponent.rating || 0);
    if (!bestWin || opponentRating > bestWin.opponentRating) {
      bestWin = {
        opponentName: opponent.user?.name || opponent.user?.id || 'opponent',
        opponentRating
      };
    }
  } else {
    losses += 1;
  }
}

const gamesPlayed = wins + draws + losses;
const preferredPerf = Object.keys(perfCounts).sort((a, b) => perfCounts[b] - perfCounts[a])[0] || 'rapid';
const perfs = profile.perfs || {};
const standardPerf = perfs[preferredPerf] || perfs.rapid || perfs.blitz || perfs.classical || perfs.bullet || {};
const currentRating = standardPerf.rating || 'No active rating this month';
const puzzlePerf = perfs.puzzle || {};
const noActivity = gamesPlayed === 0;

const ratingChange = ratingDiffCount
  ? (ratingDiffTotal > 0 ? `+${ratingDiffTotal}` : String(ratingDiffTotal))
  : (noActivity ? 'No activity' : '0');

const puzzleActivity = noActivity
  ? 'No activity received this month.'
  : (puzzlePerf.rating
      ? `Puzzle rating ${puzzlePerf.rating} · ${puzzlePerf.games || 0} puzzles`
      : 'No puzzle activity recorded this month.');

const bestResult = noActivity
  ? 'No activity received this month.'
  : (bestWin
      ? `Win vs ${bestWin.opponentName}${bestWin.opponentRating ? ` (${bestWin.opponentRating})` : ''}`
      : 'No win found this month');

const message = noActivity
  ? `No Lichess activity found for ${username} in ${request.monthLabel}.`
  : `Lichess snapshot fetched for ${username}: ${gamesPlayed} rated games in ${request.monthLabel}.`;

return [{ json: {
  ok: true,
  data: {
    taskId: request.taskId,
    studentId: request.studentId,
    studentName: request.studentName,
    lichessId: username,
    month: request.monthLabel,
    monthKey: request.monthKey,
    source: 'n8n-lichess-v2',
    noActivity,
    studentRating: String(currentRating),
    gamesPlayed: String(gamesPlayed),
    wins: String(wins),
    draws: String(draws),
    losses: String(losses),
    ratingChange,
    puzzleActivity,
    bestResult,
    perfType: preferredPerf,
    message
  }
} }];
